// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.TripleTerm;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.Intersection;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.TripleRef;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationCase;
import org.eclipse.rdf4j.query.algebra.equivalence.SemanticsTarget;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

import example.ApplicationTupleExpr;

class SemanticsValidatorTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI SUBJECT = VF.createIRI("urn:test:subject");
	private static final IRI PREDICATE = VF.createIRI("urn:test:predicate");
	private static final TripleTerm TRIPLE = VF.createTripleTerm(SUBJECT, PREDICATE, VF.createLiteral("object"));

	private final SemanticsValidator validator = new SemanticsValidator();

	@Test
	void rejectsApplicationDefinedAndUnregisteredNativeNodes() {
		SemanticsValidator.Validation application = validator.validate(
				new ApplicationTupleExpr(),
				SemanticsTarget.RDF4J_RUNTIME);
		SemanticsValidator.Validation nativeSubclass = validator.validate(
				new org.eclipse.rdf4j.query.algebra.UnregisteredNativeTupleExpr(),
				SemanticsTarget.RDF4J_RUNTIME);

		assertFalse(application.isSupported());
		assertTrue(application.getReason().startsWith("Application-defined algebra node"));
		assertFalse(nativeSubclass.isSupported());
		assertTrue(nativeSubclass.getReason().startsWith("Native RDF4J algebra node"));
	}

	@Test
	void enforcesRuntimeOnlyAndSparql12NodeProfiles() {
		Intersection runtimeOnly = new Intersection(new SingletonSet(), new SingletonSet());
		TripleRef sparql12 = new TripleRef(Var.of("s"), Var.of("p"), Var.of("o"), Var.of("triple"));

		assertTrue(validator.validate(runtimeOnly, SemanticsTarget.RDF4J_RUNTIME).isSupported());
		assertFalse(validator.validate(runtimeOnly, SemanticsTarget.SPARQL_1_2_DRAFT).isSupported());
		assertFalse(validator.validate(sparql12, SemanticsTarget.SPARQL_1_1).isSupported());
		assertTrue(validator.validate(sparql12, SemanticsTarget.SPARQL_1_2_DRAFT).isSupported());
	}

	@Test
	void checksValuesStoredInVarsConstantsAndAssignments() {
		Literal directional = VF.createLiteral("text", "en", Literal.BaseDirection.LTR);
		BindingSetAssignment unset = new BindingSetAssignment();
		MapBindingSet row = new MapBindingSet();
		row.setBinding("triple", TRIPLE);
		BindingSetAssignment values = new BindingSetAssignment();
		values.setBindingSets(List.of(row));

		assertFalse(validator.validate(Var.of("triple", TRIPLE), SemanticsTarget.SPARQL_1_1).isSupported());
		assertFalse(validator.validate(new ValueConstant(directional), SemanticsTarget.SPARQL_1_1).isSupported());
		assertFalse(validator.validate(unset, SemanticsTarget.RDF4J_RUNTIME).isSupported());
		assertEquals(
				"BindingSetAssignment has no binding sets: evaluation would fail before producing a result",
				validator.validate(unset, SemanticsTarget.RDF4J_RUNTIME).getReason());
		assertFalse(validator.validate(values, SemanticsTarget.SPARQL_1_1).isSupported());
		assertTrue(validator.validate(values, SemanticsTarget.SPARQL_1_2_DRAFT).isSupported());
	}

	@Test
	void checksStatementsAndIncomingBindingsInEvaluationCases() {
		EvaluationCase rdf12Statement = EvaluationCase.builder("triple statement")
				.addStatement(VF.createStatement(SUBJECT, PREDICATE, TRIPLE))
				.build();
		MapBindingSet bindings = new MapBindingSet();
		bindings.setBinding("triple", TRIPLE);
		EvaluationCase rdf12Binding = EvaluationCase.builder("triple binding")
				.initialBindings(bindings)
				.build();
		EvaluationCase ordinary = EvaluationCase.builder("ordinary")
				.addStatement(VF.createStatement(SUBJECT, PREDICATE, VF.createLiteral("ordinary")))
				.build();

		assertFalse(validator.validate(rdf12Statement, SemanticsTarget.SPARQL_1_1).isSupported());
		assertFalse(validator.validate(rdf12Binding, SemanticsTarget.SPARQL_1_1).isSupported());
		assertTrue(validator.validate(ordinary, SemanticsTarget.SPARQL_1_1).isSupported());
		assertTrue(validator.validate(rdf12Statement, SemanticsTarget.SPARQL_1_2_DRAFT).isSupported());
	}
}
